import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/RecordingIndicators.css';

function RecordingIndicators() {
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [indicatorsData, setIndicatorsData] = useState([]);
  const [isEditing, setIsEditing] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [newRecord, setNewRecord] = useState({
    date: new Date().toISOString().split('T')[0],
    FEV1: '',
    FVC: '',
    PEF: '',
    respiratory_rate: '',
    pulse: '',
    cough: '',
    breathlessness: '',
    wheezing: '',
    chest_tightness: '',
    nighttime_awakenings: '',
    medicine: ''
  });

  useEffect(() => {
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    const fetchRecords = async () => {
      try {
        const response = await fetch(`http://localhost:5000/api/health-records/${user_id}`);
        if (!response.ok) {
          throw new Error('Failed to fetch records');
        }
        const data = await response.json();
        setIndicatorsData(data);
      } catch (error) {
        console.error('Error fetching records:', error);
        setError('Failed to load records');
      }
    };

    fetchRecords();
  }, [navigate]);

  const handleInputChange = (e, field) => {
    const { value } = e.target;
    setNewRecord(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const handleSaveRecord = async () => {
    setError('');
    setSuccess('');

    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    // Перевірка чи всі поля заповнені
    if (!Object.values(newRecord).every(value => value !== '')) {
      setError('All fields are required');
      return;
    }

    try {
      const response = await fetch('http://localhost:5000/api/health-records', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ...newRecord,
          user_id: parseInt(user_id)
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to add record');
      }

      // Refresh records
      const recordsResponse = await fetch(`http://localhost:5000/api/health-records/${user_id}`);
      const recordsData = await recordsResponse.json();
      setIndicatorsData(recordsData);
      setSuccess('Record added successfully');

      // Clear form and hide editing row
      setNewRecord({
        date: new Date().toISOString().split('T')[0],
        FEV1: '',
        FVC: '',
        PEF: '',
        respiratory_rate: '',
        pulse: '',
        cough: '',
        breathlessness: '',
        wheezing: '',
        chest_tightness: '',
        nighttime_awakenings: '',
        medicine: ''
      });
      setIsEditing(false);
    } catch (err) {
      setError(err.message);
    }
  };

  const handleAddNewRow = () => {
    setIsEditing(true);
  };

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    navigate('/');
  };

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  return (
    <div className={`recording-indicators-container ${isSidebarOpen ? 'sidebar-open' : ''}`}>
      <div className="top-bar">
        <div className="top-center">
          <h1>Asthma Monitoring</h1>
        </div>
        <div className="nav-buttons">
          <button onClick={handleLogout} className="logout-button">
            Logout
          </button>
        </div>
      </div>
      <div className="content">
        <h2>Recording Indicators</h2>
        {error && <div className="error-message">{error}</div>}
        {success && <div className="success-message">{success}</div>}

        <div className="table-container">
          <table className="indicators-table">
            <thead>
              <tr>
                <th>Date</th>
                <th>FEV1</th>
                <th>FVC</th>
                <th>PEF</th>
                <th>Respiratory Rate</th>
                <th>Pulse</th>
                <th>Cough</th>
                <th>Breathlessness</th>
                <th>Wheezing</th>
                <th>Chest Tightness</th>
                <th>Nighttime Awakenings</th>
                <th>Medicine</th>
              </tr>
            </thead>
            <tbody>
              {indicatorsData.map((row, index) => (
                <tr key={index}>
                  <td>{new Date(row.date).toLocaleDateString()}</td>
                  <td>{row.FEV1}</td>
                  <td>{row.FVC}</td>
                  <td>{row.PEF}</td>
                  <td>{row.respiratory_rate}</td>
                  <td>{row.pulse}</td>
                  <td>{row.cough}</td>
                  <td>{row.breathlessness}</td>
                  <td>{row.wheezing}</td>
                  <td>{row.chest_tightness}</td>
                  <td>{row.nighttime_awakenings}</td>
                  <td>{row.medicine}</td>
                </tr>
              ))}
              {isEditing && (
                <tr className="editing-row">
                  <td>
                    <input
                      type="date"
                      value={newRecord.date}
                      onChange={(e) => handleInputChange(e, 'date')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      step="0.1"
                      placeholder="FEV1"
                      value={newRecord.FEV1}
                      onChange={(e) => handleInputChange(e, 'FEV1')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      step="0.1"
                      placeholder="FVC"
                      value={newRecord.FVC}
                      onChange={(e) => handleInputChange(e, 'FVC')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      placeholder="PEF"
                      value={newRecord.PEF}
                      onChange={(e) => handleInputChange(e, 'PEF')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      placeholder="Rate"
                      value={newRecord.respiratory_rate}
                      onChange={(e) => handleInputChange(e, 'respiratory_rate')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      placeholder="Pulse"
                      value={newRecord.pulse}
                      onChange={(e) => handleInputChange(e, 'pulse')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      placeholder="0-3"
                      min="0"
                      max="3"
                      value={newRecord.cough}
                      onChange={(e) => handleInputChange(e, 'cough')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      placeholder="0-1"
                      min="0"
                      max="1"
                      value={newRecord.breathlessness}
                      onChange={(e) => handleInputChange(e, 'breathlessness')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      placeholder="0-1"
                      min="0"
                      max="1"
                      value={newRecord.wheezing}
                      onChange={(e) => handleInputChange(e, 'wheezing')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      placeholder="0-1"
                      min="0"
                      max="1"
                      value={newRecord.chest_tightness}
                      onChange={(e) => handleInputChange(e, 'chest_tightness')}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      placeholder="Count"
                      min="0"
                      value={newRecord.nighttime_awakenings}
                      onChange={(e) => handleInputChange(e, 'nighttime_awakenings')}
                    />
                  </td>
                  <td>
                    <input
                      type="text"
                      placeholder="Medicine"
                      value={newRecord.medicine}
                      onChange={(e) => handleInputChange(e, 'medicine')}
                    />
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
        <div className="button-container">
          {!isEditing && (
            <button onClick={handleAddNewRow} className="add-row-button">
              Add New Row
            </button>
          )}
          {isEditing && (
            <button onClick={handleSaveRecord} className="save-row-button">
              Save Record
            </button>
          )}
        </div>
      </div>

      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
          <h2>Menu</h2>
        </div>
        <nav className="sidebar-nav">
          <button onClick={() => navigate('/dashboard')}>
            Home
          </button>
          <button onClick={() => navigate('/recording-indicators')}>
            Recording Indicators
          </button>
          <button onClick={() => navigate('/exacerbation-forecast')}>
            Exacerbation Forecast
          </button>
          <button onClick={() => navigate('/graphs-of-changes')}>
            Graphs of Changes
          </button>
          <button onClick={() => navigate('/medication-diary')}>
            Medication Diary
          </button>
        </nav>
      </div>
      <div className="floating-menu-button" onClick={toggleSidebar}>
        <span></span>
        <span></span>
        <span></span>
      </div>
    </div>
  );
}

export default RecordingIndicators;
